+#[inline]
+fn dot_product(a: &[f32], b: &[f32]) -> f32 {
+    if *SIMD_DOT_ENABLED {
+        dot_product_simd(a, b)
+    } else {
+        dot_product_scalar(a, b)
+    }
+}
